import { Container, Row, Col, Card, Button, Badge } from "react-bootstrap";
import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import api from "../services/api"; // Sử dụng instance axios đã tạo
import "../styles/navbar.css"; // Tận dụng style của bạn

function HomePage() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const user = JSON.parse(localStorage.getItem("user") || "null");
  const navigate = useNavigate();

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        // Gọi API lấy danh sách sự kiện từ backend
        const response = await api.get("/events");
        setEvents(response.data);
      } catch (error) {
        console.error("Lỗi khi tải sự kiện:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchEvents();
  }, []);

  return (
    <Container className="py-5">
      {/* Phần chào mừng */}
      <Row className="mb-5">
        <Col md={12}>
          {user ? (
            <div className="welcome-section p-4 bg-light rounded-4 shadow-sm">
              <h2 className="fw-bold text-primary">Chào mừng trở lại, {user.full_name}!</h2>
              <p className="text-muted mb-0">Sẵn sàng bùng nổ với những đêm nhạc đỉnh cao nhất chưa?</p>
            </div>
          ) : (
            <div className="text-center py-5 bg-dark text-white rounded-4 shadow-lg">
              <h1 className="display-5 fw-bold">Trải Nghiệm Concert Thế Hệ Mới</h1>
              <p className="lead">Mua vé an toàn, chuyển nhượng minh bạch trên nền tảng Blockchain.</p>
              <Button size="lg" variant="primary" onClick={() => navigate("/login")} className="px-5 mt-3">
                Tham gia ngay
              </Button>
            </div>
          )}
        </Col>
      </Row>

      <h3 className="fw-bold mb-4">Sự kiện nổi bật</h3>

      {loading ? (
        <div className="text-center p-5">Đang tải danh sách sự kiện...</div>
      ) : (
        <Row className="g-4">
          {events.length > 0 ? (
            events.map((event) => (
              <Col md={4} key={event.id}>
                <Card className="h-100 shadow-sm border-0 rounded-4 overflow-hidden card-hover">
                  {/* Banner sự kiện */}
                  <div style={{ height: "200px", overflow: "hidden" }}>
                    <Card.Img 
                      variant="top" 
                      src={event.banner_image || "https://via.placeholder.com/400x200?text=No+Image"} 
                      style={{ objectFit: "cover", height: "100%" }}
                    />
                  </div>
                  
                  <Card.Body className="p-4 d-flex flex-column">
                    <div className="d-flex justify-content-between align-items-start mb-2">
                      <Badge bg="info" className="text-dark">Music</Badge>
                      <small className="text-muted font-monospace">
                        {new Date(event.event_date).toLocaleDateString('vi-VN')}
                      </small>
                    </div>

                    <Card.Title className="fw-bold fs-4">{event.title}</Card.Title>
                    
                    <Card.Text className="text-secondary flex-grow-1">
                      <i className="fa fa-map-marker-alt me-2 text-danger"></i>
                      {event.location}
                    </Card.Text>

                    <Button 
                      variant="outline-primary" 
                      className="w-100 mt-3 fw-bold py-2"
                      onClick={() => navigate(`/event/${event.id}`)}
                    >
                      Xem chi tiết & Đặt vé
                    </Button>
                  </Card.Body>
                </Card>
              </Col>
            ))
          ) : (
            <Col md={12} className="text-center">
              <div className="p-5 border rounded-4 bg-light">
                <p className="m-0 text-muted">Hiện chưa có sự kiện nào được mở bán.</p>
              </div>
            </Col>
          )}
        </Row>
      )}
    </Container>
  );
}

export default HomePage;
